import test from 'node:test';
import assert from 'node:assert/strict';

import { createCompressionDecider } from '../src/compress-response.mjs';

test('spaced deployment configuration matches parameterized handler responses end to end', () => {
  const shouldCompress = createCompressionDecider({
    COMPRESS_TYPES: ' Application/JSON , text/csv '
  });

  assert.equal(shouldCompress('application/json; charset=utf-8'), true);
  assert.equal(shouldCompress('TEXT/CSV; header=present'), true);
  assert.equal(shouldCompress('image/png; profile=compact'), false);
  assert.equal(shouldCompress(undefined), false);
});
